import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();
  useTheme(); // Triggers theme injection

  const handleLogin = async (e) => {
    e.preventDefault();
    const tid = toast.loading('SYNCHRONIZING...');
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: tid });
      navigate('/dashboard');
    } catch (err) {
      toast.error('AUTH_FAILED', { id: tid });
    }
  };

  return (
    <div className="cyber-card reveal-data">
      <div className="flex flex-col items-center mb-8">
        <div className="p-3 bg-[var(--accent-glow)] rounded-2xl mb-4">
          <Cpu className="text-[var(--accent-primary)] animate-pulse" size={32} />
        </div>
        <h2 className="text-2xl font-light tracking-[0.3em] uppercase">Access_Gate</h2>
        <p className="text-[10px] text-[var(--text-muted)] tracking-widest mt-2">SECURE_NODE_V3</p>
      </div>

      <form onSubmit={handleLogin} className="space-y-6">
        <div>
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest block mb-2 ml-1">
            Registry_Email
          </label>
          <input 
            type="email" 
            className="cyber-input" 
            placeholder="operator@finify.ai"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        <div className="relative">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest block mb-2 ml-1">
            Security_Key
          </label>
          <input 
            type={showPass ? "text" : "password"} 
            className="cyber-input" 
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <button 
            type="button" 
            onClick={() => setShowPass(!showPass)}
            className="absolute right-4 bottom-4 text-[var(--text-muted)] hover:text-[var(--accent-primary)]"
          >
            {showPass ? <FaEyeSlash /> : <FaEye />}
          </button>
        </div>

        <button type="submit" className="cyber-btn mt-4">
          <ShieldCheck size={16} /> Connect_to_Terminal
        </button>
      </form>

      <div className="mt-8 pt-6 border-t border-[var(--surface-border)] text-center">
        <Link to="/register" className="text-[10px] text-[var(--accent-primary)] uppercase tracking-widest hover:underline">
          Initialize_New_Identity
        </Link>
      </div>
    </div>
  );
};

export default LoginPage;
